ow.lane // require to have lane, for combining data later if one sample is sequenced by more than one lanes\n            def reads = [] // create empty list for files\n            reads.add(file(row.fastq_1)) // add R1 fq\n            reads.add(file(row.fastq_2)) // add R2 fq\n            return [ meta, reads ]\n        }\n        .set { ch_input }\n    ch_input.view() // View channel here\n    // Run workflow\n    FASTQC (\n        ch_input\n    )   \n}\n'})}),"\n",(0,i.jsxs)(n.p,{children:["We can rerun with the input is ",(0,i.jsx)(n.code,{children:"samplesheet.csv"})," content as below"]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-bash",children:"sample,lane,fastq_1,fastq_2\nsample1,1,https://raw.githubusercontent.com/nf-core/test-datasets/modules/data/genomics/homo_sapiens/illumina/fastq/test_1.fastq.gz,https://raw.githubusercontent.com/nf-core/test-datasets/modules/data/genomics/homo_sapiens/illumina/fastq/test_2.fastq.gz\nsample2,1,https://raw.githubusercontent.com/nf-core/test-datasets/modules/data/genomics/homo_sapiens/illumina/fastq/test_1.fastq.gz,https://raw.githubusercontent.com/nf-core/test-datasets/modules/data/genomics/homo_sapiens/illumina/fastq/test_2.fastq.gz\n"})}),"\n",(0,i.jsxs)(n.p,{children:["We can rerun and see how that there are 2 tuples which matches with the input file. From now, it is the true meaning of distribution tasks, running 2 FASTQC at the same time on my machine, has the resource limitation via ",(0,i.jsx)(n.code,{children:"docker"})]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-bash",children:"nextflow run main.nf --input samplesheet.csv -resume\n"})}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{alt:"samplesheet.csv",src:t(8302).A+"",width:"1701",height:"455"})}),"\n",(0,i.jsx)(n.h3,{id:"38-connect-modules",children:"3.8 Connect modules"}),"\n",(0,i.jsxs)(n.p,{children:["A pipeline is a chain of tools working together, where each step\u2019s output feeds into the next. Let